111	void trace_lte(ev_data *d, int direction, int rnti_type, int rnti,
112	        int frame, int subframe, void *buf, int bufsize, int preamble,
113	        int sr_rnti)
114	{
115	  ssize_t ret;
116	  int fsf;
117	  int i;
118	  d->buf.osize = 0;
119	  PUTS(&d->buf, MAC_LTE_START_STRING);
120	  PUTC(&d->buf, FDD_RADIO);
121	  PUTC(&d->buf, direction);
122	  PUTC(&d->buf, rnti_type);
123	
124	  if (rnti_type == C_RNTI || rnti_type == RA_RNTI) {
125	    PUTC(&d->buf, MAC_LTE_RNTI_TAG);
126	    PUTC(&d->buf, (rnti>>8) & 255);
127	    PUTC(&d->buf, rnti & 255);
128	
129	    /* put UE id */
130	    if (rnti < 0 || rnti > 65535) { printf("bad rnti!\n"); exit(1); }
131	    /* if no UE id allocated for this rnti then allocate the next one */
132	    if (d->lte_rnti_to_ueid[rnti] == -1) {
133	      d->lte_rnti_to_ueid[rnti] = d->lte_next_ue_id;
134	      d->lte_next_ue_id++;
135	    }
136	
137	    PUTC(&d->buf, MAC_LTE_UEID_TAG);
138	    PUTC(&d->buf, (d->lte_rnti_to_ueid[rnti]>>8) & 255);
139	    PUTC(&d->buf, d->lte_rnti_to_ueid[rnti] & 255);
140	  }
141	
142	  /* for newer version of wireshark? */
143	  fsf = (frame << 4) + subframe;
144	  /* for older version? */
145	  //fsf = subframe;
146	  PUTC(&d->buf, MAC_LTE_FRAME_SUBFRAME_TAG);
147	  PUTC(&d->buf, (fsf>>8) & 255);
148	  PUTC(&d->buf, fsf & 255);
149	
150	  if (preamble != NO_PREAMBLE) {
151	    PUTC(&d->buf, MAC_LTE_SEND_PREAMBLE_TAG);
152	    PUTC(&d->buf, preamble);
153	    PUTC(&d->buf, 0); /* rach attempt - always 0 for us (not sure of this) */
154	  }
155	
156	  if (sr_rnti != NO_SR_RNTI) {
157	    PUTC(&d->buf, MAC_LTE_SR_TAG);
158	    PUTC(&d->buf, 0); /* number of items byte 1 */
159	    PUTC(&d->buf, 1); /* number of items byte 2 */
160	
161	    /* put UE id */
162	    if (sr_rnti < 0 || sr_rnti > 65535) { printf("bad sr rnti!\n"); exit(1); }
163	    /* if no UE id allocated for this rnti then allocate the next one */
164	    if (d->lte_rnti_to_ueid[sr_rnti] == -1) {
165	      d->lte_rnti_to_ueid[sr_rnti] = d->lte_next_ue_id;
166	      d->lte_next_ue_id++;
167	    }
168	    PUTC(&d->buf, (d->lte_rnti_to_ueid[sr_rnti]>>8) & 255);
169	    PUTC(&d->buf, d->lte_rnti_to_ueid[sr_rnti] & 255);
170	
171	    PUTC(&d->buf, (sr_rnti>>8) & 255);
172	    PUTC(&d->buf, sr_rnti & 255);
173	  }
174	
175	  PUTC(&d->buf, MAC_LTE_PAYLOAD_TAG);
176	
177	  for (i = 0; i < bufsize; i++)
178	    PUTC(&d->buf, ((char *)buf)[i]);
179	
180	  ret = sendto(d->socket, d->buf.obuf, d->buf.osize, 0,
181	               (struct sockaddr *)&d->to, sizeof(struct sockaddr_in));
182	
183	  if (ret != d->buf.osize) abort();
184	}
